/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across all channels.
 *
 * DECISION CHANGE (Agent 9): The original model (Agent 3) assumed email-only.
 * With SMS (Agent 8) and webhook (Agent 6) adapters now in place, preferences
 * must support per-channel settings. The email-only assumption is explicitly
 * invalidated. SMS and webhook preferences are optional fields for backward
 * compatibility — when absent, defaults apply (opt-out model).
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 * - 'none': do not send email notifications at all
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Per-channel notification preferences for email.
 */
export interface EmailNotificationPreferences {
  /** Master toggle — when false, no emails are sent regardless of other settings. */
  enabled: boolean;
  /** Delivery cadence. Only applies when enabled is true. */
  frequency: EmailFrequency;
  /** Per-category opt-in/out. Only categories set to true will be delivered. */
  categories: Record<NotificationType, boolean>;
}

/**
 * Per-channel notification preferences for SMS.
 */
export interface SmsNotificationPreferences {
  /** Master toggle — when false, no SMS messages are sent. */
  enabled: boolean;
  /** Per-category opt-in/out. */
  categories: Record<NotificationType, boolean>;
}

/**
 * Per-channel notification preferences for webhook.
 */
export interface WebhookNotificationPreferences {
  /** Master toggle — when false, no webhooks are fired. */
  enabled: boolean;
  /** Per-category opt-in/out. */
  categories: Record<NotificationType, boolean>;
}

/**
 * Full notification preferences for a user.
 *
 * `sms` and `webhook` are optional for backward compatibility — existing
 * records that only have `email` will continue to work. When a channel's
 * preferences are absent, all notifications for that channel are allowed
 * (opt-out model).
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  sms?: SmsNotificationPreferences;
  webhook?: WebhookNotificationPreferences;
  updatedAt: Date;
}

/**
 * Input for updating email notification preferences (all fields optional).
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categories?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating SMS notification preferences (all fields optional).
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  categories?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating webhook notification preferences (all fields optional).
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  categories?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Returns default email notification preferences — all categories enabled,
 * immediate delivery.
 */
export function defaultEmailPreferences(): EmailNotificationPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: {
      'order-confirmation': true,
      'order-status-update': true,
      'user-welcome': true,
      'user-update': true,
      'system-alert': true,
    },
  };
}

/**
 * Returns default SMS notification preferences — all categories enabled.
 */
export function defaultSmsPreferences(): SmsNotificationPreferences {
  return {
    enabled: true,
    categories: {
      'order-confirmation': true,
      'order-status-update': true,
      'user-welcome': true,
      'user-update': true,
      'system-alert': true,
    },
  };
}

/**
 * Returns default webhook notification preferences — all categories enabled.
 */
export function defaultWebhookPreferences(): WebhookNotificationPreferences {
  return {
    enabled: true,
    categories: {
      'order-confirmation': true,
      'order-status-update': true,
      'user-welcome': true,
      'user-update': true,
      'system-alert': true,
    },
  };
}

/**
 * Preferences validation — pure validation functions for notification preferences.
 *
 * These validators contain no side effects and no database calls.
 * They evaluate preference rules against in-memory preference data.
 */

import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';

/**
 * Check whether a notification is allowed by the user's preferences.
 *
 * Rules:
 * 1. If no preferences exist (null), notifications are allowed (opt-out model).
 * 2. For email: check enabled, frequency, and category.
 * 3. For SMS: check enabled and category (if sms preferences exist).
 * 4. For webhook: check enabled and category (if webhook preferences exist).
 * 5. If a channel's preferences are not set, notifications are allowed (backward compat).
 * 6. Channels without preference support (e.g. in-app) are always allowed.
 */
export function isNotificationAllowed(
  prefs: UserNotificationPreferences | null,
  channel: NotificationChannel,
  type: NotificationType,
): boolean {
  // No preferences stored — default is to send everything
  if (!prefs) {
    return true;
  }

  if (channel === 'email') {
    return isEmailAllowed(prefs, type);
  }

  if (channel === 'sms') {
    return isSmsAllowed(prefs, type);
  }

  if (channel === 'webhook') {
    return isWebhookAllowed(prefs, type);
  }

  // Channels without preference support (e.g. in-app) are always allowed
  return true;
}

function isEmailAllowed(prefs: UserNotificationPreferences, type: NotificationType): boolean {
  if (!prefs.email.enabled) {
    return false;
  }

  if (prefs.email.frequency === 'none') {
    return false;
  }

  if (prefs.email.categories[type] === false) {
    return false;
  }

  return true;
}

function isSmsAllowed(prefs: UserNotificationPreferences, type: NotificationType): boolean {
  // No SMS preferences set — allow (backward compat / opt-out model)
  if (!prefs.sms) {
    return true;
  }

  if (!prefs.sms.enabled) {
    return false;
  }

  if (prefs.sms.categories[type] === false) {
    return false;
  }

  return true;
}

function isWebhookAllowed(prefs: UserNotificationPreferences, type: NotificationType): boolean {
  // No webhook preferences set — allow (backward compat / opt-out model)
  if (!prefs.webhook) {
    return true;
  }

  if (!prefs.webhook.enabled) {
    return false;
  }

  if (prefs.webhook.categories[type] === false) {
    return false;
  }

  return true;
}

/**
 * Repository for user notification preferences.
 *
 * Extends BaseRepository with a lookup-by-userId method,
 * since preferences are keyed to a user rather than queried in bulk.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    const prefs: UserNotificationPreferences = {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as UserNotificationPreferences['email']['frequency'],
        categories: JSON.parse(record['emailCategories'] as string) as Record<NotificationType, boolean>,
      },
      updatedAt: new Date(record['updatedAt'] as string),
    };

    // SMS preferences (optional — may not exist in older records)
    if (record['smsEnabled'] !== undefined) {
      prefs.sms = {
        enabled: record['smsEnabled'] as boolean,
        categories: JSON.parse(record['smsCategories'] as string) as Record<NotificationType, boolean>,
      };
    }

    // Webhook preferences (optional — may not exist in older records)
    if (record['webhookEnabled'] !== undefined) {
      prefs.webhook = {
        enabled: record['webhookEnabled'] as boolean,
        categories: JSON.parse(record['webhookCategories'] as string) as Record<NotificationType, boolean>,
      };
    }

    return prefs;
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      updatedAt: entity.updatedAt.toISOString(),
    };

    if (entity.sms) {
      record['smsEnabled'] = entity.sms.enabled;
      record['smsCategories'] = JSON.stringify(entity.sms.categories);
    }

    if (entity.webhook) {
      record['webhookEnabled'] = entity.webhook.enabled;
      record['webhookCategories'] = JSON.stringify(entity.webhook.categories);
    }

    return record;
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((pref) => pref.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD for notification preferences across all channels (email,
 * SMS, webhook) and a check method that the NotificationService uses
 * before sending.
 *
 * Depends on:
 * - PreferencesRepository for persistence
 * - UserRepository to validate user existence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  UserNotificationPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { defaultEmailPreferences, defaultSmsPreferences, defaultWebhookPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import { isNotificationAllowed } from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepo: PreferencesRepository,
    private userRepo: UserRepository,
  ) {}

  /**
   * Get preferences for a user. If none exist yet, returns default preferences
   * without persisting them (lazy initialization on first update).
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (existing) {
      return existing;
    }

    // Return transient defaults — not persisted until the user explicitly updates
    return {
      id: '',
      userId,
      email: defaultEmailPreferences(),
      updatedAt: new Date(),
    };
  }

  /**
   * Update email notification preferences for a user.
   * Creates the preferences record on first update (upsert semantics).
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserNotificationPreferences {
    const user = this.userRepo.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const existing = this.preferencesRepo.findByUserId(userId);

    if (existing) {
      const updatedEmail = {
        ...existing.email,
        ...('enabled' in input ? { enabled: input.enabled! } : {}),
        ...('frequency' in input ? { frequency: input.frequency! } : {}),
        categories: {
          ...existing.email.categories,
          ...(input.categories ?? {}),
        },
      };

      const updated = this.preferencesRepo.update(existing.id, {
        email: updatedEmail,
        updatedAt: new Date(),
      } as Partial<UserNotificationPreferences>);

      this.logger.info(`Updated email preferences for user ${userId}`);
      return updated;
    }

    // First-time save — merge input onto defaults
    const defaults = defaultEmailPreferences();
    const emailPrefs = {
      ...defaults,
      ...('enabled' in input ? { enabled: input.enabled! } : {}),
      ...('frequency' in input ? { frequency: input.frequency! } : {}),
      categories: {
        ...defaults.categories,
        ...(input.categories ?? {}),
      },
    };

    const prefs: UserNotificationPreferences = {
      id: generatePreferencesId(),
      userId,
      email: emailPrefs,
      updatedAt: new Date(),
    };

    this.preferencesRepo.save(prefs);
    this.logger.info(`Created email preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Update SMS notification preferences for a user.
   * Creates the preferences record on first update (upsert semantics).
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateSmsPreferencesInput,
  ): UserNotificationPreferences {
    const user = this.userRepo.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const existing = this.preferencesRepo.findByUserId(userId);

    if (existing) {
      const currentSms = existing.sms ?? defaultSmsPreferences();
      const updatedSms = {
        ...currentSms,
        ...('enabled' in input ? { enabled: input.enabled! } : {}),
        categories: {
          ...currentSms.categories,
          ...(input.categories ?? {}),
        },
      };

      const updated = this.preferencesRepo.update(existing.id, {
        sms: updatedSms,
        updatedAt: new Date(),
      } as Partial<UserNotificationPreferences>);

      this.logger.info(`Updated SMS preferences for user ${userId}`);
      return updated;
    }

    // First-time save — merge input onto defaults
    const defaults = defaultSmsPreferences();
    const smsPrefs = {
      ...defaults,
      ...('enabled' in input ? { enabled: input.enabled! } : {}),
      categories: {
        ...defaults.categories,
        ...(input.categories ?? {}),
      },
    };

    const prefs: UserNotificationPreferences = {
      id: generatePreferencesId(),
      userId,
      email: defaultEmailPreferences(),
      sms: smsPrefs,
      updatedAt: new Date(),
    };

    this.preferencesRepo.save(prefs);
    this.logger.info(`Created SMS preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Update webhook notification preferences for a user.
   * Creates the preferences record on first update (upsert semantics).
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateWebhookPreferencesInput,
  ): UserNotificationPreferences {
    const user = this.userRepo.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const existing = this.preferencesRepo.findByUserId(userId);

    if (existing) {
      const currentWebhook = existing.webhook ?? defaultWebhookPreferences();
      const updatedWebhook = {
        ...currentWebhook,
        ...('enabled' in input ? { enabled: input.enabled! } : {}),
        categories: {
          ...currentWebhook.categories,
          ...(input.categories ?? {}),
        },
      };

      const updated = this.preferencesRepo.update(existing.id, {
        webhook: updatedWebhook,
        updatedAt: new Date(),
      } as Partial<UserNotificationPreferences>);

      this.logger.info(`Updated webhook preferences for user ${userId}`);
      return updated;
    }

    // First-time save — merge input onto defaults
    const defaults = defaultWebhookPreferences();
    const webhookPrefs = {
      ...defaults,
      ...('enabled' in input ? { enabled: input.enabled! } : {}),
      categories: {
        ...defaults.categories,
        ...(input.categories ?? {}),
      },
    };

    const prefs: UserNotificationPreferences = {
      id: generatePreferencesId(),
      userId,
      email: defaultEmailPreferences(),
      webhook: webhookPrefs,
      updatedAt: new Date(),
    };

    this.preferencesRepo.save(prefs);
    this.logger.info(`Created webhook preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Check whether a notification should be delivered to a user on a given channel.
   * Returns true if the notification is allowed, false if it should be suppressed.
   */
  shouldSend(
    userId: string,
    channel: NotificationChannel,
    type: NotificationType,
  ): boolean {
    const prefs = this.preferencesRepo.findByUserId(userId) ?? null;
    const allowed = isNotificationAllowed(prefs, channel, type);

    if (!allowed) {
      this.logger.debug(`Notification ${type} on ${channel} suppressed for user ${userId}`);
    }

    return allowed;
  }
}

