import { describe, it, expect } from 'vitest';
import { isNotificationAllowed } from '../../src/validators/preferences.validator.js';
import { defaultEmailPreferences, defaultSmsPreferences, defaultWebhookPreferences } from '../../src/models/user-preferences.js';
import type { UserNotificationPreferences } from '../../src/models/user-preferences.js';

function makePrefs(
  overrides?: Partial<Pick<UserNotificationPreferences, 'email' | 'sms' | 'webhook'>>,
): UserNotificationPreferences {
  return {
    id: 'pref-1',
    userId: 'user-1',
    email: overrides?.email ?? defaultEmailPreferences(),
    sms: overrides?.sms,
    webhook: overrides?.webhook,
    updatedAt: new Date(),
  };
}

describe('Preferences Validators', () => {
  describe('isNotificationAllowed', () => {
    it('should allow when prefs are null (opt-out model)', () => {
      expect(isNotificationAllowed(null, 'email', 'order-confirmation')).toBe(true);
    });

    it('should allow when all defaults are in place', () => {
      const prefs = makePrefs();
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(true);
    });

    it('should suppress when email is disabled', () => {
      const prefs = makePrefs({ email: { ...defaultEmailPreferences(), enabled: false } });
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should suppress when frequency is none', () => {
      const prefs = makePrefs({ email: { ...defaultEmailPreferences(), frequency: 'none' } });
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should suppress when specific category is disabled', () => {
      const defaults = defaultEmailPreferences();
      const prefs = makePrefs({
        email: {
          ...defaults,
          categories: {
            ...defaults.categories,
            'order-confirmation': false,
          },
        },
      });
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should allow other categories when one is disabled', () => {
      const defaults = defaultEmailPreferences();
      const prefs = makePrefs({
        email: {
          ...defaults,
          categories: {
            ...defaults.categories,
            'order-confirmation': false,
          },
        },
      });
      expect(isNotificationAllowed(prefs, 'email', 'order-status-update')).toBe(true);
    });

    it('should always allow in-app channel', () => {
      const prefs = makePrefs({ email: { ...defaultEmailPreferences(), enabled: false } });
      expect(isNotificationAllowed(prefs, 'in-app', 'order-confirmation')).toBe(true);
    });

    it('should always allow non-email channels when prefs are null', () => {
      expect(isNotificationAllowed(null, 'webhook', 'system-alert')).toBe(true);
    });
  });

  describe('isNotificationAllowed — SMS channel', () => {
    it('should allow SMS when no sms preferences are set (backward compat)', () => {
      const prefs = makePrefs();
      expect(isNotificationAllowed(prefs, 'sms', 'order-confirmation')).toBe(true);
    });

    it('should allow SMS when sms preferences are enabled', () => {
      const prefs = makePrefs({ sms: defaultSmsPreferences() });
      expect(isNotificationAllowed(prefs, 'sms', 'order-confirmation')).toBe(true);
    });

    it('should suppress SMS when sms is disabled', () => {
      const prefs = makePrefs({ sms: { ...defaultSmsPreferences(), enabled: false } });
      expect(isNotificationAllowed(prefs, 'sms', 'order-confirmation')).toBe(false);
    });

    it('should suppress SMS when specific category is disabled', () => {
      const defaults = defaultSmsPreferences();
      const prefs = makePrefs({
        sms: {
          ...defaults,
          categories: { ...defaults.categories, 'system-alert': false },
        },
      });
      expect(isNotificationAllowed(prefs, 'sms', 'system-alert')).toBe(false);
      expect(isNotificationAllowed(prefs, 'sms', 'order-confirmation')).toBe(true);
    });

    it('should not affect email when sms is disabled', () => {
      const prefs = makePrefs({ sms: { ...defaultSmsPreferences(), enabled: false } });
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(true);
    });
  });

  describe('isNotificationAllowed — webhook channel', () => {
    it('should allow webhook when no webhook preferences are set (backward compat)', () => {
      const prefs = makePrefs();
      expect(isNotificationAllowed(prefs, 'webhook', 'order-confirmation')).toBe(true);
    });

    it('should allow webhook when webhook preferences are enabled', () => {
      const prefs = makePrefs({ webhook: defaultWebhookPreferences() });
      expect(isNotificationAllowed(prefs, 'webhook', 'order-confirmation')).toBe(true);
    });

    it('should suppress webhook when webhook is disabled', () => {
      const prefs = makePrefs({ webhook: { ...defaultWebhookPreferences(), enabled: false } });
      expect(isNotificationAllowed(prefs, 'webhook', 'order-confirmation')).toBe(false);
    });

    it('should suppress webhook when specific category is disabled', () => {
      const defaults = defaultWebhookPreferences();
      const prefs = makePrefs({
        webhook: {
          ...defaults,
          categories: { ...defaults.categories, 'user-welcome': false },
        },
      });
      expect(isNotificationAllowed(prefs, 'webhook', 'user-welcome')).toBe(false);
      expect(isNotificationAllowed(prefs, 'webhook', 'order-confirmation')).toBe(true);
    });

    it('should not affect email when webhook is disabled', () => {
      const prefs = makePrefs({ webhook: { ...defaultWebhookPreferences(), enabled: false } });
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(true);
    });
  });

  describe('isNotificationAllowed — multi-channel independence', () => {
    it('should allow disabling email while keeping sms and webhook enabled', () => {
      const prefs = makePrefs({
        email: { ...defaultEmailPreferences(), enabled: false },
        sms: defaultSmsPreferences(),
        webhook: defaultWebhookPreferences(),
      });
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(false);
      expect(isNotificationAllowed(prefs, 'sms', 'order-confirmation')).toBe(true);
      expect(isNotificationAllowed(prefs, 'webhook', 'order-confirmation')).toBe(true);
    });

    it('should allow different category settings per channel', () => {
      const prefs = makePrefs({
        email: {
          ...defaultEmailPreferences(),
          categories: { ...defaultEmailPreferences().categories, 'system-alert': false },
        },
        sms: {
          ...defaultSmsPreferences(),
          categories: { ...defaultSmsPreferences().categories, 'order-confirmation': false },
        },
      });
      // Email: system-alert off, order-confirmation on
      expect(isNotificationAllowed(prefs, 'email', 'system-alert')).toBe(false);
      expect(isNotificationAllowed(prefs, 'email', 'order-confirmation')).toBe(true);
      // SMS: order-confirmation off, system-alert on
      expect(isNotificationAllowed(prefs, 'sms', 'order-confirmation')).toBe(false);
      expect(isNotificationAllowed(prefs, 'sms', 'system-alert')).toBe(true);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { defaultEmailPreferences, defaultSmsPreferences, defaultWebhookPreferences } from '../../src/models/user-preferences.js';
import type { User } from '../../src/models/user.js';

function createTestUser(db: Database, overrides: Partial<User> = {}): User {
  const user: User = {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
  const repo = new UserRepository(db);
  return repo.save(user);
}

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return default preferences when none are saved', () => {
      const prefs = service.getPreferences('user-0001');

      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories['order-confirmation']).toBe(true);
      expect(prefs.email.categories['system-alert']).toBe(true);
    });

    it('should return saved preferences when they exist', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { frequency: 'daily-digest' });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.id).toBe('pref-0001');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should create preferences on first update', () => {
      createTestUser(db);
      const prefs = service.updateEmailPreferences('user-0001', {
        frequency: 'weekly-digest',
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.frequency).toBe('weekly-digest');
      expect(prefs.email.enabled).toBe(true); // default preserved
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updateEmailPreferences('nonexistent', { enabled: false }),
      ).toThrow('User not found: nonexistent');
    });

    it('should update enabled flag', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { enabled: false });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.email.enabled).toBe(false);
    });

    it('should update individual categories without affecting others', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', {
        categories: { 'order-confirmation': false },
      });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.email.categories['order-confirmation']).toBe(false);
      expect(prefs.email.categories['order-status-update']).toBe(true);
      expect(prefs.email.categories['system-alert']).toBe(true);
    });

    it('should merge updates onto existing preferences', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { frequency: 'daily-digest' });
      service.updateEmailPreferences('user-0001', {
        categories: { 'user-welcome': false },
      });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.email.frequency).toBe('daily-digest'); // first update preserved
      expect(prefs.email.categories['user-welcome']).toBe(false); // second update applied
    });

    it('should update frequency on existing preferences', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { frequency: 'daily-digest' });
      service.updateEmailPreferences('user-0001', { frequency: 'none' });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.email.frequency).toBe('none');
    });
  });

  describe('updateSmsPreferences', () => {
    it('should create preferences with SMS settings on first update', () => {
      createTestUser(db);
      const prefs = service.updateSmsPreferences('user-0001', { enabled: true });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.categories['order-confirmation']).toBe(true);
      // Email defaults should also be present
      expect(prefs.email.enabled).toBe(true);
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updateSmsPreferences('nonexistent', { enabled: false }),
      ).toThrow('User not found: nonexistent');
    });

    it('should disable SMS notifications', () => {
      createTestUser(db);
      service.updateSmsPreferences('user-0001', { enabled: false });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.sms!.enabled).toBe(false);
    });

    it('should update SMS categories without affecting email', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { frequency: 'daily-digest' });
      service.updateSmsPreferences('user-0001', {
        categories: { 'system-alert': false },
      });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.sms!.categories['system-alert']).toBe(false);
      expect(prefs.sms!.categories['order-confirmation']).toBe(true);
      expect(prefs.email.frequency).toBe('daily-digest'); // email unchanged
    });

    it('should merge SMS updates onto existing SMS preferences', () => {
      createTestUser(db);
      service.updateSmsPreferences('user-0001', { categories: { 'user-welcome': false } });
      service.updateSmsPreferences('user-0001', { enabled: false });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.sms!.enabled).toBe(false);
      expect(prefs.sms!.categories['user-welcome']).toBe(false); // preserved from first update
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should create preferences with webhook settings on first update', () => {
      createTestUser(db);
      const prefs = service.updateWebhookPreferences('user-0001', { enabled: true });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.categories['order-confirmation']).toBe(true);
      expect(prefs.email.enabled).toBe(true);
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updateWebhookPreferences('nonexistent', { enabled: false }),
      ).toThrow('User not found: nonexistent');
    });

    it('should disable webhook notifications', () => {
      createTestUser(db);
      service.updateWebhookPreferences('user-0001', { enabled: false });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.webhook!.enabled).toBe(false);
    });

    it('should update webhook categories independently', () => {
      createTestUser(db);
      service.updateWebhookPreferences('user-0001', {
        categories: { 'order-status-update': false },
      });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.webhook!.categories['order-status-update']).toBe(false);
      expect(prefs.webhook!.categories['order-confirmation']).toBe(true);
    });
  });

  describe('shouldSend', () => {
    it('should allow notifications when no preferences exist', () => {
      expect(service.shouldSend('user-0001', 'email', 'order-confirmation')).toBe(true);
    });

    it('should suppress when email is disabled', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { enabled: false });

      expect(service.shouldSend('user-0001', 'email', 'order-confirmation')).toBe(false);
      expect(service.shouldSend('user-0001', 'email', 'system-alert')).toBe(false);
    });

    it('should suppress when frequency is none', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { frequency: 'none' });

      expect(service.shouldSend('user-0001', 'email', 'order-confirmation')).toBe(false);
    });

    it('should suppress when specific category is disabled', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', {
        categories: { 'order-confirmation': false },
      });

      expect(service.shouldSend('user-0001', 'email', 'order-confirmation')).toBe(false);
      expect(service.shouldSend('user-0001', 'email', 'order-status-update')).toBe(true);
    });

    it('should allow when email is enabled and category is enabled', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', {
        enabled: true,
        frequency: 'daily-digest',
        categories: { 'order-confirmation': true },
      });

      expect(service.shouldSend('user-0001', 'email', 'order-confirmation')).toBe(true);
    });

    it('should suppress SMS when sms is disabled', () => {
      createTestUser(db);
      service.updateSmsPreferences('user-0001', { enabled: false });

      expect(service.shouldSend('user-0001', 'sms', 'order-confirmation')).toBe(false);
    });

    it('should allow SMS when no sms preferences exist (backward compat)', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { enabled: false });

      // SMS has no preferences set, so it should still be allowed
      expect(service.shouldSend('user-0001', 'sms', 'order-confirmation')).toBe(true);
    });

    it('should suppress webhook when webhook is disabled', () => {
      createTestUser(db);
      service.updateWebhookPreferences('user-0001', { enabled: false });

      expect(service.shouldSend('user-0001', 'webhook', 'system-alert')).toBe(false);
    });

    it('should allow webhook when no webhook preferences exist (backward compat)', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { enabled: false });

      expect(service.shouldSend('user-0001', 'webhook', 'system-alert')).toBe(true);
    });

    it('should allow in-app channel regardless of preferences', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', { enabled: false });

      expect(service.shouldSend('user-0001', 'in-app', 'system-alert')).toBe(true);
    });

    it('should check per-channel category preferences independently', () => {
      createTestUser(db);
      service.updateEmailPreferences('user-0001', {
        categories: { 'system-alert': false },
      });
      service.updateSmsPreferences('user-0001', {
        categories: { 'system-alert': true },
      });

      expect(service.shouldSend('user-0001', 'email', 'system-alert')).toBe(false);
      expect(service.shouldSend('user-0001', 'sms', 'system-alert')).toBe(true);
    });
  });
});

describe('defaultEmailPreferences', () => {
  it('should return all categories enabled', () => {
    const defaults = defaultEmailPreferences();
    expect(defaults.enabled).toBe(true);
    expect(defaults.frequency).toBe('immediate');
    expect(Object.values(defaults.categories).every(Boolean)).toBe(true);
  });

  it('should return independent copies', () => {
    const a = defaultEmailPreferences();
    const b = defaultEmailPreferences();
    a.categories['order-confirmation'] = false;
    expect(b.categories['order-confirmation']).toBe(true);
  });
});

